int main() {
    char obfuscation[100];
    scanf("%s", obfuscation);
    char letters[] = "abcdefghijklmnopqrstuvwxyz";

    int i = strlen(obfuscation);
    char posibility[] = "NO";

    while (i) {
        if (obfuscation[0] != letters[0]) {
            strcpy(posibility, "NO");
            break;
        } else {
            while (strchr(obfuscation, letters[0]) != NULL) {
                char *p = strchr(obfuscation, letters[0]);
                memmove(p, p + 1, strlen(p));
                i--;
                if (strlen(obfuscation) == 0) {
                    strcpy(posibility, "YES");
                    break;
                }
            }
            memmove(letters, letters + 1, strlen(letters));
        }
    }

    printf("%s\n", posibility);
    return 0;
}
